import React, { useEffect, useState } from 'react';
import { api } from '../utils/api';

const DOSES = ['1ère dose', '2ème dose', '3ème dose', 'Rappel', 'Annuelle', 'Dose unique'];

const EMPTY = {
  patientId: '', vaccin: '', dose: '1ère dose',
  dateAdministration: new Date().toISOString().slice(0, 10),
  dateProchaineDose: '', medecin: '', centre: '',
  lotNumero: '', statut: 'complete', notes: ''
};

function VaccinModal({ vaccination, patients, vaccins, onClose, onSave }) {
  const [form, setForm] = useState(vaccination || EMPTY);

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    const data = { ...form, dateProchaineDose: form.dateProchaineDose || null };
    if (vaccination?.id) {
      await api.updateVaccination(vaccination.id, data);
    } else {
      await api.createVaccination(data);
    }
    onSave();
  };

  const inputStyle = { width: '100%', padding: '12px 16px', borderRadius: '8px', border: '1px solid #eaebef', outline: 'none', fontSize: '14px', background: '#f4f5f9' };
  const labelStyle = { fontSize: '12px', fontWeight: 700, color: '#8a94a6', display: 'block', marginBottom: '6px', textTransform: 'uppercase' };

  return (
    <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(29, 33, 41, 0.4)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000 }} onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={{ background: 'white', borderRadius: '16px', padding: '32px', width: '100%', maxWidth: '600px', boxShadow: '0 10px 40px rgba(0,0,0,0.1)', maxHeight: '90vh', overflowY: 'auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <h2 style={{ fontFamily: 'Syne, sans-serif', fontSize: '20px', fontWeight: 800, color: '#1d2129' }}>{vaccination?.id ? 'Modifier la vaccination' : 'Déclarer une vaccination'}</h2>
          <button style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#8a94a6' }} onClick={onClose}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
          </button>
        </div>
        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>

          <div>
            <label style={labelStyle}>Patient *</label>
            <select required value={form.patientId} onChange={e => set('patientId', e.target.value)} style={inputStyle}>
              <option value="" disabled>-- Sélectionner le dossier patient --</option>
              {patients.map(p => <option key={p.id} value={p.id}>{p.nom} {p.prenom}</option>)}
            </select>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '16px' }}>
            <div>
              <label style={labelStyle}>Vaccin Administré *</label>
              <select required value={form.vaccin} onChange={e => set('vaccin', e.target.value)} style={inputStyle}>
                <option value="" disabled>-- Sélectionner --</option>
                {vaccins.map(v => <option key={v} value={v}>{v}</option>)}
              </select>
            </div>
            <div>
              <label style={labelStyle}>Dose</label>
              <select value={form.dose} onChange={e => set('dose', e.target.value)} style={inputStyle}>
                {DOSES.map(d => <option key={d} value={d}>{d}</option>)}
              </select>
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
            <div>
              <label style={labelStyle}>Date d'administration *</label>
              <input type="date" required value={form.dateAdministration} onChange={e => set('dateAdministration', e.target.value)} style={inputStyle} />
            </div>
            <div>
              <label style={labelStyle}>Date de prochain rappel</label>
              <input type="date" value={form.dateProchaineDose || ''} onChange={e => set('dateProchaineDose', e.target.value)} style={inputStyle} />
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
            <div>
              <label style={labelStyle}>Médecin / Infirmier</label>
              <input value={form.medecin} onChange={e => set('medecin', e.target.value)} placeholder="Personnel soignant" style={inputStyle} />
            </div>
            <div>
              <label style={labelStyle}>Numéro de lot</label>
              <input value={form.lotNumero} onChange={e => set('lotNumero', e.target.value)} placeholder="EX: LOT-2024-XX" style={{...inputStyle, fontFamily: 'monospace', fontWeight: 'bold'}} />
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '16px' }}>
            <div>
              <label style={labelStyle}>Centre / Lieu</label>
              <input value={form.centre} onChange={e => set('centre', e.target.value)} placeholder="Hôpital, Clinique..." style={inputStyle} />
            </div>
            <div>
              <label style={labelStyle}>Statut</label>
              <select value={form.statut} onChange={e => set('statut', e.target.value)} style={inputStyle}>
                <option value="complete">Terminée</option>
                <option value="a_venir">Programmée</option>
                <option value="annule">Annulée</option>
              </select>
            </div>
          </div>

          <div>
            <label style={labelStyle}>Suites & Observations Médicales</label>
            <textarea rows={2} value={form.notes} onChange={e => set('notes', e.target.value)} placeholder="Alergies, effets secondaires observés (fièvre, etc.)..." style={{...inputStyle, resize: 'vertical' }} />
          </div>

          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '12px', marginTop: '16px' }}>
            <button type="button" onClick={onClose} style={{ padding: '12px 24px', borderRadius: '50px', border: '1px solid #eaebef', background: 'white', fontWeight: 700, cursor: 'pointer', color: '#8a94a6' }}>Annuler</button>
            <button type="submit" style={{ padding: '12px 24px', borderRadius: '50px', border: 'none', background: '#0056ff', fontWeight: 700, cursor: 'pointer', color: 'white' }}>
              {vaccination?.id ? 'Mettre à jour' : 'Valider la vaccination'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

const STATUT_STYLES = {
  complete: { bg: '#ebf2ff', color: '#0056ff', label: 'Terminée' },
  a_venir: { bg: '#fff5eb', color: '#f59e0b', label: 'Programmée' },
  annule: { bg: '#f4f5f9', color: '#8a94a6', label: 'Annulée' }
};

export default function Vaccinations({ selectedPatient, setSelectedPatient }) {
  const [vaccinations, setVaccinations] = useState([]);
  const [patients, setPatients] = useState([]);
  const [vaccins, setVaccins] = useState([]);
  const [modal, setModal] = useState(null);
  const [filterPatient, setFilterPatient] = useState(selectedPatient?.id || '');
  const [filterStatut, setFilterStatut] = useState('');
  const [loading, setLoading] = useState(true);

  const load = async () => {
    setLoading(true);
    const params = {};
    if (filterPatient) params.patientId = filterPatient;
    if (filterStatut) params.statut = filterStatut;
    const [v, p, vx] = await Promise.all([
      api.getVaccinations(params),
      api.getPatients(),
      api.getVaccinsDisponibles()
    ]);
    setVaccinations(v);
    setPatients(p);
    setVaccins(vx);
    setLoading(false);
  };

  useEffect(() => { load(); }, [filterPatient, filterStatut]);

  useEffect(() => {
    if (selectedPatient) setFilterPatient(selectedPatient.id);
  }, [selectedPatient]);

  const handleDelete = async (id) => {
    if (window.confirm('Voulez-vous vraiment supprimer cet enregistrement vaccinal ?')) {
      await api.deleteVaccination(id);
      load();
    }
  };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '32px' }}>
        <div>
          <h1 style={{ fontFamily: 'Syne', fontSize: 26, fontWeight: 800, color: '#1d2129', marginBottom: 4 }}>Historique Vaccinal</h1>
          <p style={{ color: '#8a94a6', fontSize: 14 }}>Registre complet des actes médicaux et suivi épidémiologique.</p>
        </div>
        <button onClick={() => setModal('create')} style={{ background: '#0056ff', color: 'white', border: 'none', padding: '12px 24px', borderRadius: '50px', fontWeight: 700, display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer', boxShadow: '0 4px 15px rgba(0,86,255,0.2)' }}>
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 2l-2 2 4 4 2-2-4-4z"></path><path d="M10 4L2 12l2 2-2 2 2 2 2-2 2 2 8-8-8-8z"></path><line x1="14" y1="10" x2="4" y2="20"></line></svg>
          Saisir un Vaccin
        </button>
      </div>

      <div style={{ display: 'flex', gap: 12, marginBottom: 24 }}>
        <select
          style={{ padding: '10px 16px', borderRadius: '50px', border: '1px solid #eaebef', background: 'white', outline: 'none', fontSize: 13, color: '#1d2129', minWidth: '240px' }}
          value={filterPatient}
          onChange={e => { setFilterPatient(e.target.value); setSelectedPatient(null); }}
        >
          <option value="">Tous les patients confondus</option>
          {patients.map(p => (
            <option key={p.id} value={p.id}>👤 {p.nom} {p.prenom}</option>
          ))}
        </select>

        <select
          style={{ padding: '10px 16px', borderRadius: '50px', border: '1px solid #eaebef', background: 'white', outline: 'none', fontSize: 13, color: '#1d2129', minWidth: '180px' }}
          value={filterStatut}
          onChange={e => setFilterStatut(e.target.value)}
        >
          <option value="">Tous statuts</option>
          <option value="complete">Terminées</option>
          <option value="a_venir">Programmées futures</option>
        </select>

        {(filterPatient || filterStatut) && (
          <button style={{ background: 'none', border: 'none', color: '#ec4899', fontSize: 13, fontWeight: 700, cursor: 'pointer', marginLeft: 8 }} onClick={() => { setFilterPatient(''); setFilterStatut(''); setSelectedPatient(null); }}>
            ✕ Réinitialiser
          </button>
        )}
      </div>

      <div className="card" style={{ border: 'none', padding: '24px', boxShadow: '0 2px 10px rgba(0,0,0,0.02)' }}>
        {loading ? (
          <div style={{ textAlign: 'center', padding: 40, color: '#8a94a6' }}>Chargement...</div>
        ) : vaccinations.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '60px 20px', color: '#8a94a6', background: '#f4f5f9', borderRadius: '12px' }}>
            Aucun enregistrement ne correspond aux filtres actuels.
          </div>
        ) : (
          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
              <thead>
                <tr style={{ color: '#8a94a6', borderBottom: '1px solid #eaebef' }}>
                  <th style={{ padding: '16px 8px', fontWeight: 600, fontSize: 12, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Date</th>
                  <th style={{ padding: '16px 8px', fontWeight: 600, fontSize: 12, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Sujet (Patient)</th>
                  <th style={{ padding: '16px 8px', fontWeight: 600, fontSize: 12, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Produit Vaccinal</th>
                  <th style={{ padding: '16px 8px', fontWeight: 600, fontSize: 12, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Détails lot & dose</th>
                  <th style={{ padding: '16px 8px', fontWeight: 600, fontSize: 12, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Rappel prévu</th>
                  <th style={{ padding: '16px 8px', fontWeight: 600, fontSize: 12, textTransform: 'uppercase', letterSpacing: '0.5px' }}>État</th>
                  <th style={{ padding: '16px 8px', textAlign: 'right' }}></th>
                </tr>
              </thead>
              <tbody>
                {vaccinations.map((v, i) => {
                  const styleRef = STATUT_STYLES[v.statut] || STATUT_STYLES.complete;
                  return (
                    <tr key={v.id} style={{ borderBottom: i < vaccinations.length-1 ? '1px solid #eaebef' : 'none' }}>
                      <td style={{ padding: '16px 8px', fontWeight: 600, fontSize: 13, color: '#1d2129' }}>
                        {new Date(v.dateAdministration).toLocaleDateString('fr-FR')}
                      </td>

                      <td style={{ padding: '16px 8px', fontWeight: 700, fontSize: 14, color: '#1d2129' }}>
                        {v.patient}
                      </td>

                      <td style={{ padding: '16px 8px' }}>
                        <div style={{ fontWeight: 800, color: '#0056ff', fontSize: 14 }}>{v.vaccin}</div>
                        <div style={{ fontSize: 11, color: '#8a94a6', marginTop: 2 }}>{v.centre || 'Centre non spécifié'}</div>
                      </td>

                      <td style={{ padding: '16px 8px' }}>
                        <div style={{ color: '#1d2129', fontSize: 13, fontWeight: 500 }}>{v.dose}</div>
                        {v.lotNumero && <div style={{ fontSize: 11, fontFamily: 'monospace', fontWeight: 600, color: '#8a94a6', marginTop: 4 }}>LOT: {v.lotNumero}</div>}
                      </td>

                      <td style={{ padding: '16px 8px', fontSize: 13 }}>
                        {v.dateProchaineDose 
                          ? <span style={{ fontWeight: 600, color: '#1d2129' }}>{new Date(v.dateProchaineDose).toLocaleDateString('fr-FR')}</span>
                          : <span style={{ color: '#8a94a6' }}>Aucun</span>}
                      </td>

                      <td style={{ padding: '16px 8px' }}>
                        <span style={{ background: styleRef.bg, color: styleRef.color, padding: '4px 10px', borderRadius: '6px', fontSize: 11, fontWeight: 800, textTransform: 'uppercase' }}>
                          {styleRef.label}
                        </span>
                      </td>

                      <td style={{ padding: '16px 8px', textAlign: 'right' }}>
                        <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
                          <button onClick={() => setModal(v)} style={{ background: '#f4f5f9', border: '1px solid #eaebef', borderRadius: '8px', padding: '8px', cursor: 'pointer', color: '#8a94a6' }} title="Modifier">
                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 20h9"></path><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"></path></svg>
                          </button>
                          <button onClick={() => handleDelete(v.id)} style={{ background: '#fce7f3', border: '1px solid #fbcfe8', borderRadius: '8px', padding: '8px', cursor: 'pointer', color: '#ec4899' }} title="Supprimer">
                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"></path></svg>
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {modal && (
        <VaccinModal
          vaccination={modal === 'create' ? null : modal}
          patients={patients}
          vaccins={vaccins}
          onClose={() => setModal(null)}
          onSave={() => { setModal(null); load(); }}
        />
      )}
    </div>
  );
}
